using MaintenanceCMMS.Infrastructure.Data.PostgreSql.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace MaintenanceCMMS.Infrastructure.Data.PostgreSql.Configurations;
public sealed class LaborRateConfiguration:IEntityTypeConfiguration<LaborRateEntity>{public void Configure(EntityTypeBuilder<LaborRateEntity> b){b.ToTable("tarifas_hh");b.ConfigureBase();b.Property(x=>x.Code).HasColumnName("codigo").HasMaxLength(80).IsRequired();b.Property(x=>x.Specialty).HasColumnName("especialidad").HasMaxLength(120);b.Property(x=>x.HourlyRate).HasColumnName("tarifa_hora").HasColumnType("numeric(14,2)");b.HasIndex(x=>x.Code).IsUnique();}}
public sealed class CostEntryConfiguration:IEntityTypeConfiguration<CostEntryEntity>{public void Configure(EntityTypeBuilder<CostEntryEntity> b){b.ToTable("costos");b.ConfigureBase();b.Property(x=>x.CostNumber).HasColumnName("numero").HasMaxLength(80).IsRequired();b.Property(x=>x.Category).HasColumnName("categoria").HasMaxLength(50).IsRequired();b.Property(x=>x.Amount).HasColumnName("monto").HasColumnType("numeric(14,2)");b.Property(x=>x.Currency).HasColumnName("moneda").HasMaxLength(10);b.Property(x=>x.Description).HasColumnName("descripcion").HasMaxLength(1000);b.Property(x=>x.OccurredAtUtc).HasColumnName("fecha_utc").HasColumnType("timestamptz");b.Property(x=>x.ContractCode).HasColumnName("contrato_codigo").HasMaxLength(80);b.Property(x=>x.SupplierRut).HasColumnName("proveedor_rut").HasMaxLength(40);b.Property(x=>x.UnitCost).HasColumnName("costo_unitario").HasColumnType("numeric(14,2)");b.Property(x=>x.Quantity).HasColumnName("cantidad").HasColumnType("numeric(14,2)");b.Property(x=>x.DocumentUrl).HasColumnName("documento_url").HasMaxLength(1000);b.HasIndex(x=>x.CostNumber).IsUnique();b.HasIndex(x=>new{x.FaenaId,x.OccurredAtUtc});b.HasIndex(x=>x.WorkOrderId);}}
public sealed class PaymentStatementConfiguration:IEntityTypeConfiguration<PaymentStatementEntity>{public void Configure(EntityTypeBuilder<PaymentStatementEntity> b){b.ToTable("estados_pago");b.ConfigureBase();b.Property(x=>x.StatementNumber).HasColumnName("numero").HasMaxLength(80).IsRequired();b.Property(x=>x.SupplierRut).HasColumnName("proveedor_rut").HasMaxLength(40);b.Property(x=>x.Amount).HasColumnName("monto").HasColumnType("numeric(14,2)");b.Property(x=>x.Status).HasColumnName("estado").HasMaxLength(30);b.HasIndex(x=>x.StatementNumber).IsUnique();b.HasIndex(x=>new{x.SupplierRut,x.Status});}}